async def init_cities(db: AsyncSession):
    result = await db.execute(select(City).limit(1))
    if result.scalar_one_or_none():
        logger.info("Cities already initialized, skipping")
        return

    for city_data in CITIES_DATA:
        db.add(City(**city_data))

    await db.flush()
    logger.info("Initialized %d cities", len(CITIES_DATA))
